import React, { useEffect, useState } from 'react';
import api from '../api/api'; // Tu instancia de axios
import { FaEye, FaFilePdf, FaTrash } from 'react-icons/fa'; // Iconos

const HistorialCotizaciones = () => {
  const [cotizaciones, setCotizaciones] = useState([]);

  const cargarCotizaciones = async () => {
    try {
      const res = await api.get('/cotizaciones');
      setCotizaciones(res.data);
    } catch (error) {
      console.error("Error al cargar historial:", error);
    }
  };

  useEffect(() => {
    cargarCotizaciones();
  }, []);

  return (
    <div className="p-6 bg-gray-900 min-h-screen text-white">
      <h2 className="text-2xl font-bold mb-6 text-blue-400">Historial de Cotizaciones</h2>
      
      <div className="overflow-x-auto bg-gray-800 rounded-lg shadow-lg">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-gray-700 text-gray-300">
              <th className="p-4">Fecha</th>
              <th className="p-4">Cliente</th>
              <th className="p-4">Total</th>
              <th className="p-4">Estado</th>
              <th className="p-4">Acciones</th>
            </tr>
          </thead>
          <tbody>
            {cotizaciones.map((c) => (
              <tr key={c._id} className="border-b border-gray-700 hover:bg-gray-750 transition">
                <td className="p-4">{new Date(c.createdAt).toLocaleDateString()}</td>
                <td className="p-4">{c.Nombre} {c.Apellido}</td>
                <td className="p-4 font-bold text-green-400">${c.Total.toFixed(2)}</td>
                <td className="p-4">
                  <span className="px-2 py-1 rounded bg-yellow-900 text-yellow-400 text-xs">
                    {c.estado || 'Pendiente'}
                  </span>
                </td>
                <td className="p-4 flex gap-3">
                  <button title="Ver Detalle" className="text-blue-400 hover:text-blue-300"><FaEye /></button>
                  <button title="Exportar PDF" className="text-red-400 hover:text-red-300"><FaFilePdf /></button>
                  <button title="Eliminar" className="text-gray-500 hover:text-red-500"><FaTrash /></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default HistorialCotizaciones;
